scwin.f_checkDate = async function () {
  var adptStDt = ds_retrieveResult.getCellData(ds_retrieveResult.getRowCount() - 1, "adptStDt");
  var adptEndDt = ds_retrieveResult.getCellData(ds_retrieveResult.getRowCount() - 1, "adptEndDt");
  if (adptEndDt != "99999999") {
    if (!(await $c.gus.cfIsAfterDate($p, adptStDt, adptEndDt, false))) {
      //$c.win.alert(adptStDt+"    "+adptEndDt);
      $c.win.alert($p, "적용종료일을 적용시작일보다 이후로 입력하십시오.");
      ds_retrieveResult.setCellData(row, "adptEndDt", "99999999");
      return false;
    }
  }
  return true;
};
scwin.f_checkTime = async function () {
  var row = ds_retrieveResult.getRowCount();
  var adptStDt = ds_retrieveResult.getCellData(ds_retrieveResult.getRowCount(), "adptStDt");
  var timeYn = lc_hhEchYn.getValue();
  for (var i = 0; i < row; i++) {
    var workStHh = adptStDt + ds_retrieveResult.getCellData(i, "workStHh") + "00"; //근무시작시간
    var workEndHh = adptStDt + ds_retrieveResult.getCellData(i, "workEndHh") + "00"; //근무종료시간
    var saturdayWorkStHh = adptStDt + ds_retrieveResult.getCellData(i, "saturdayWorkStHh") + "00"; //토요일근무시작시간
    var saturdayWorkEndHh = adptStDt + ds_retrieveResult.getCellData(i, "saturdayWorkEndHh") + "00"; //토요일근무종료시간

    var extdStHh = adptStDt + ds_retrieveResult.getCellData(i, "extdStHh") + "00"; //연장시작시간
    var extdEndHh = adptStDt + ds_retrieveResult.getCellData(i, "extdEndHh") + "00"; //연장종료시간
    var saturdayExtdStHh = adptStDt + ds_retrieveResult.getCellData(i, "saturdayExtdStHh") + "00"; //토요일연장시작시간
    var saturdayExtdEndHh = adptStDt + ds_retrieveResult.getCellData(i, "saturdayExtdEndHh") + "00"; //토요일연장종료시간

    var midngtStHh = adptStDt + ds_retrieveResult.getCellData(i, "midngtStHh") + "00"; //심야시작시간
    var midngtEndHh = adptStDt + ds_retrieveResult.getCellData(i, "midngtEndHh") + "00"; //심야종료시간
    var saturdayMidngtStHh = adptStDt + ds_retrieveResult.getCellData(i, "saturdayMidngtStHh") + "00"; //토요일심야시작시간
    var saturdayMidngtEndHh = adptStDt + ds_retrieveResult.getCellData(i, "saturdayMidngtEndHh") + "00"; //토요일심야종료시간

    var dnrStHh = adptStDt + ds_retrieveResult.getCellData(i, "dnrStHh") + "00"; //저녁식사시작시간
    var dnrEndHh = adptStDt + ds_retrieveResult.getCellData(i, "dnrEndHh") + "00"; //저녁식사종료시간

    var sprStHh = adptStDt + ds_retrieveResult.getCellData(i, "sprStHh") + "00"; //야식시작시간
    var sprEndHh = adptStDt + ds_retrieveResult.getCellData(i, "sprEndHh") + "00"; //야식종료시간

    var breakfastStHh = adptStDt + ds_retrieveResult.getCellData(i, "breakfastStHh") + "00"; //아침식사시작시간
    var breakfastEndHh = adptStDt + ds_retrieveResult.getCellData(i, "breakfastEndHh") + "00"; //아침식사종료시간

    var nextDdBreakfastStHh = adptStDt + ds_retrieveResult.getCellData(i, "nextDdBreakfastStHh") + "00"; //익일아침식사시작시간
    var nextDdBreakfastEndHh = adptStDt + ds_retrieveResult.getCellData(i, "nextDdBreakfastEndHh") + "00"; //익일아침식사종료시간

    if (!(await scwin.cfIsAfterTime(workStHh, workEndHh, false, i))) {
      $c.win.alert($p, i + 1 + "번째 Row의 근무종료시간을 근무시작시간 이후로 선택하십이오.");
      lc_workEndHh.focus();
      return false;
    }
    if (!(await scwin.cfIsAfterTime(saturdayWorkStHh, saturdayWorkEndHh, false, i))) {
      $c.win.alert($p, i + 1 + "번째 Row의 토요일근무종료시간을 토요일근무시작시간 이후로 선택하십이오.");
      lc_saturdayWorkEndHh.focus();
      return false;
    }
    if (timeYn != 1) {
      if (!(await scwin.cfIsAfterTime(extdStHh, extdEndHh, false, i))) {
        $c.win.alert($p, i + 1 + "번째 Row의 연장종료시간을 연장시작시간 이후로 선택하십이오.");
        lc_extdEndHh.focus();
        return false;
      }
      if (!(await scwin.cfIsAfterTime(saturdayExtdStHh, saturdayExtdEndHh, false, i))) {
        $c.win.alert($p, i + 1 + "번째 Row의 토요일연장종료시간을 토요일심야시작시간 이후로 선택하십이오.");
        lc_saturdayExtdEndHh.focus();
        return false;
      }
    }
    if (!(await scwin.cfIsAfterTime(dnrStHh, dnrEndHh, false, i))) {
      $c.win.alert($p, i + 1 + "번째 Row의 저녁식사종료시간을 저녁식사시작시간 이후로 선택하십이오.");
      lc_dnrEndHh.focus();
      return false;
    }
    if (!(await scwin.cfIsAfterTime(breakfastStHh, breakfastEndHh, false, i))) {
      $c.win.alert($p, i + 1 + "번째 Row의 아침식사종료시간을 아침식사시작시간 이후로 선택하십이오.");
      lc_breakfastEndHh.focus();
      return false;
    }
    if (!(await scwin.cfIsAfterTime(nextDdBreakfastStHh, nextDdBreakfastEndHh, false, i))) {
      $c.win.alert($p, i + 1 + "번째 Row의 익일아침식사종료시간을 익일아침식사시작시간 이후로 선택하십이오.");
      lc_nextDdBreakfastEndHh.focus();
      return false;
    }
  }
  return true;
};
scwin.cfIsAfterTime = function (startDate, endDate, exceptSameDate, i) {
  var sDate = startDate.toDate("YYYYMMDDHHMI");
  var eDate = endDate.toDate("YYYYMMDDHHMI");
  if (exceptSameDate != null && exceptSameDate == true) {
    if (sDate < eDate) return true;else ds_retrieveResult.setRowPosition(i);
    return false;
  } else {
    if (sDate <= eDate) return true;else ds_retrieveResult.setRowPosition(i);
    return false;
  }
};

