scwin.f_OnLoadCompleted = function (rowcnt) {
  if (rowcnt > 0) {
    $c.gus.cfEnableObjects($p, [btn_Update, btn_Save]);
  }
};
scwin.f_RowChange = function () {
  var rowstatus = ds_retrieveResult.getRowStatus(ds_retrieveResult.getRowPosition());
  var value = ds_retrieveResult.getCellData(ds_retrieveResult.getRowPosition(), "adptEndDt");
  if (value != "99999999") {
    $c.gus.cfDisableObjects($p, [btn_Update]);
  } else if (value == "99999999") {
    $c.gus.cfEnableObjects($p, [btn_Update]);
  }
  if (rowstatus == "R") {
    $c.gus.cfDisableObjects($p, [con_main, table1, table2]);
    $c.gus.cfDisableObjects($p, [ica_adptStDt, ica_wageAgrmntDt]);
  } else if (rowstatus != "R") {
    $c.gus.cfEnableObjects($p, [con_main, table1, table2]);
    $c.gus.cfDisableObjects($p, [lc_basisSalStd, lc_saturdayBasisSalStd, lc_extdSalStd, lc_saturdayExtdSalStd, lc_midngtSalStd, lc_saturdayMidngtSalStd]);
  }
};
scwin.f_checkEndDate = function () {
  var row = ds_retrieveResult.getRowCount();
  for (var i = 0; i < row; i++) {
    var value = ds_retrieveResult.getCellData(i, "adptEndDt");
    if (value == "99999999") {
      $c.win.alert($p, i + 1 + "번째 적용종료 처리되지 않은 근무기준이 존재합니다.");
      return false;
    }
  }
  return true;
};
